22	/// Pin the one surviving compile-time path literal (the `rbtd_vessels_dir!`
23	/// macro in lib.rs) to the generated source of truth. The macro must equal
24	/// `<RBTDGC_MOORINGS_DIR>/<RBTDGC_VESSELS_SUBDIR>`; if rbcc_Constants.sh changes
25	/// either, codegen updates the consts and this test fails until the macro
26	/// literal is corrected — drift caught at test time, no new dependency.
27	#[test]
28	fn rbtdtm_vessels_dir_matches_generated() {
29	    assert_eq!(
30	        crate::rbtd_vessels_dir!(),
31	        format!("{}/{}", RBTDGC_MOORINGS_DIR, RBTDGC_VESSELS_SUBDIR)
32	    );
33	}
