43	fn rbtdtm_accepts_valid_crucible_manifest() {
44	    let manifest = rbtdtm_manifest_for(RBTDRM_FIXTURE_TADMOR);
45	    assert!(rbtdrm_verify(&manifest, RBTDRM_FIXTURE_TADMOR).is_ok());
