156	fn zrbtdrc_quench_impl(ctx: &mut rbtdri_Context) {
157	    let fixture = ctx.fixture().to_string();
158	    crate::rbtdrg_info_now!("Quenching crucible...");
159	    match rbtdri_invoke(ctx, RBTDGC_CRUCIBLE_QUENCH, &[]) {
160	        Ok(r) if r.exit_code == 0 => crate::rbtdrg_info_now!("Crucible quenched"),
161	        Ok(r) => crate::rbtdrg_error_now!("quench exited {}", r.exit_code),
162	        Err(e) => crate::rbtdrg_error_now!("quench invocation failed: {}", e),
163	    }
164	
165	    crate::rbtdrg_info_now!("Verifying crucible is inactive after quench...");
166	    match rbtdri_invoke_global(ctx, RBTDGC_CRUCIBLE_ACTIVE, &[&fixture], &[]) {
167	        Ok(r) if r.exit_code != 0 => {
168	            crate::rbtdrg_info_now!("Crucible inactive confirmed");
169	        }
170	        Ok(r) => {
171	            crate::rbtdrg_error_now!(
172	                "crucible still active after quench (exit {})",
173	                r.exit_code
174	            );
175	        }
176	        Err(e) => {
177	            crate::rbtdrg_error_now!(
178	                "CrucibleActive invocation failed after quench: {}",
179	                e
180	            );
181	        }
182	    }
